import{_ as e,C as t,o as r,c as n,a2 as s,E as i}from"./chunks/framework.CpJscuQM.js";const g=JSON.parse('{"title":"Advento","description":"","frontmatter":{},"headers":[],"relativePath":"cantos/advento.md","filePath":"cantos/advento.md"}'),d={name:"cantos/advento.md"};function c(m,a,l,p,u,v){const o=t("CantosPorTempo");return r(),n("div",null,[a[0]||(a[0]=s('<h1 id="advento" tabindex="-1">Advento <a class="header-anchor" href="#advento" aria-label="Permalink to &quot;Advento&quot;">​</a></h1><h2 id="introducao" tabindex="-1">Introdução <a class="header-anchor" href="#introducao" aria-label="Permalink to &quot;Introdução&quot;">​</a></h2><p>Advento é uma palavra latina que significa aproximar-se, vir chegando aos poucos. Durante as quatro semanas do Advento, a gente se prepara para o Natal. No Advento, ouvimos as vozes sempre atuais dos profetas bíblicos, anunciando a vinda do Messias. Também ouvimos a voz de João Batista e do próprio Jesus, anunciando a proximidade do Reino de Deus.</p><p>Fonte: <a href="https://www.a12.com/redacaoa12/liturgia/advento-tempo-de-preparacao-para-o-natal" target="_blank" rel="noreferrer">A12</a></p><h3 id="como-deve-ser-o-canto-no-advento" tabindex="-1">Como deve ser o canto no Advento <a class="header-anchor" href="#como-deve-ser-o-canto-no-advento" aria-label="Permalink to &quot;Como deve ser o canto no Advento&quot;">​</a></h3><p>O numeral 305 da Instrução Geral do Missal Romano assinala que no Advento o uso do órgão e de outros instrumentos musicais deve ser marcado por uma moderação adequada de acordo com este tempo litúrgico do ano, sem expressar com antecipação a alegria plena do Natal do Senhor.</p><p>Fonte: <a href="https://www.acidigital.com/noticias/advento-7-respostas-as-perguntas-mais-comuns-94467" target="_blank" rel="noreferrer">ACI Digital</a></p><h3 id="materiais-adicionais" tabindex="-1">Materiais adicionais <a class="header-anchor" href="#materiais-adicionais" aria-label="Permalink to &quot;Materiais adicionais&quot;">​</a></h3><p><a href="https://musica.cancaonova.com/formacao-para-musicos/como-cantar-o-advento/" target="_blank" rel="noreferrer">Como Cantar o Advento - Canção Nova</a></p><h2 id="gloria" tabindex="-1">Glória <a class="header-anchor" href="#gloria" aria-label="Permalink to &quot;Glória&quot;">​</a></h2><p>Durante o Advento, não se recita o Glória porque é uma das maneiras de expressar concretamente que, enquanto dura o nosso peregrinar, falta algo para que a alegria seja completa.</p><p>Quando o Senhor estiver presente no meio do seu povo, a Igreja terá chegado à sua festa completa, com a Solenidade do Natal do Senhor, quando é cantado novamente o Glória.</p><p>O Missal Romano assinala que o Glória é recitado ou cantado aos domingos, exceto nos tempos litúrgicos do Advento e da Quaresma.</p><p>As exceções desta regra durante o Advento são a Solenidade da Imaculada Conceição, em 8 de dezembro, e a festa da Virgem de Guadalupe, em 12 de dezembro.</p><p>Fonte: <a href="https://www.acidigital.com/noticias/advento-7-respostas-as-perguntas-mais-comuns-94467" target="_blank" rel="noreferrer">ACI Digital</a></p>',15)),i(o,{tempo:"advento",momentos:["abertura","penitencial","kyrie","oferta","santo","cordeiro","comunhao"]})])}const f=e(d,[["render",c]]);export{g as __pageData,f as default};
